package pages;

import base.BasePage;
import org.openqa.selenium.WebDriver;
import static org.assertj.core.api.Assertions.*;
import static pageObjects.RegistrationPage.*;

/**
 * RegistrationPage.java
 * Page actions and assertions for Registration feature
 * Generated by: ScriptGenerationAgent | Framework: selenium-java-hybrid
 */
public class RegistrationPage extends BasePage {

    public RegistrationPage(WebDriver driver) {
        super(driver);
    }

    // ── Navigation ────────────────────────────────────────────────────────────

    public void navigate() {
        String url = getConfigProperty("BASE_URL", "http://localhost:3000");
        driver.get(url + "/register");
        waitForPageLoad();
    }

    // ── Actions ───────────────────────────────────────────────────────────────

    public void enterUsername(String username) {
        waitAndSendKeys(USERNAME_INPUT, username);
    }

    public void enterEmail(String email) {
        waitAndSendKeys(EMAIL_INPUT, email);
    }

    public void enterPassword(String password) {
        waitAndSendKeys(PASSWORD_INPUT, password);
    }

    public void enterConfirmPassword(String password) {
        waitAndSendKeys(CONFIRM_PASSWORD_INPUT, password);
    }

    public void clickRegisterButton() {
        waitAndClick(REGISTER_BUTTON);
        waitForPageLoad();
    }

    public void registerWithCredentials(String username, String email, String password) {
        enterUsername(username);
        enterEmail(email);
        enterPassword(password);
        enterConfirmPassword(password);
        clickRegisterButton();
    }

    // ── Assertions ────────────────────────────────────────────────────────────

    public void verifyRegistrationPageLoaded() {
        wait(2);
        assertThat(isElementVisible(PAGE_HEADING))
            .as("Registration page heading should be visible")
            .isTrue();
        assertThat(isElementVisible(REGISTRATION_FORM))
            .as("Registration form should be visible")
            .isTrue();
    }

    public void verifySuccessMessageDisplayed() {
        wait(2);
        assertThat(isElementVisible(SUCCESS_MESSAGE))
            .as("Success message should be visible")
            .isTrue();
    }

    public void verifyErrorMessageDisplayed() {
        wait(2);
        assertThat(isElementVisible(ERROR_MESSAGE))
            .as("Error message should be visible")
            .isTrue();
    }

    public void verifyUsernameExistsError() {
        wait(2);
        assertThat(isElementVisible(USERNAME_EXISTS_ERROR))
            .as("Username already exists error should be visible")
            .isTrue();
    }

    public void verifyMinLengthError() {
        wait(2);
        assertThat(isElementVisible(MIN_LENGTH_ERROR))
            .as("Minimum length error should be visible")
            .isTrue();
    }

    public void verifyRequiredFieldError() {
        wait(2);
        assertThat(isElementVisible(REQUIRED_FIELD_ERROR))
            .as("Required field error should be visible")
            .isTrue();
    }

    public void verifyAccountCreated() {
        wait(2);
        assertThat(isElementVisible(SUCCESS_MESSAGE))
            .as("Account should be created successfully")
            .isTrue();
    }
}
